  import java.text.SimpleDateFormat;
  import java.util.Collections;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;
  import sailpoint.object.Link;

  Log logger = LogFactory.getLog("sailpoint.targetmapping.Amita.expirationdate");

  logger.debug("Entering Ascension-Rule-IdentityAttributeTarget-Amita-ExpirationDate");


  List adLinks = new ArrayList();
  String expDate = "";

  List order = new ArrayList();

  Application app = context.getObjectByName(Application.class,"AD-AMITA");

  IdentityService identityService = new IdentityService(context);
  SimpleDateFormat adSDF = new SimpleDateFormat("yyyyMMdd");
  //if link is disabled, dont pick the value from Identity
  if(null != link && link.isDisabled()){
    logger.debug("Picking value from disabled Link");
    if (target.getName() != null) {
    expDate = link.getAttribute(target.getName());
    } else {
		expDate = "";
    }
  }else if(null != identity){
    adLinks = identityService.getLinks(identity,app);
    expDate = identity.getAttribute("ctrexpDt");

    if(expDate!=null && expDate.length()==1 && expDate.equalsIgnoreCase(" ")){
        expDate = "";
    }
    else if(Util.isNullOrEmpty(expDate) && adLinks != null && !adLinks.isEmpty()){
      for(Link adLink : adLinks){
        if(null != adLink && !adLink.isDisabled() &&   Util.isNotNullOrEmpty(adLink.getAttribute("extensionAttribute4") )){
          expDate = adLink.getAttribute("extensionAttribute4");
          try{
            order.add(adSDF.parse(expDate));
          }catch(Exception ex){
            logger.error("Exception Ascension-Rule-IdentityAttributeTarget-Amita-ExpirationDate "+ex.getMessage());
          }
        }
      }
      try{
        if(!Util.isEmpty(order)){
          Collections.sort(order,Collections.reverseOrder());
          expDate = adSDF.format( order.get(0));
        }
      }catch(Exception ex){
        logger.error("Exception Ascension-Rule-IdentityAttributeTarget-Amita-ExpirationDate "+ex.getMessage());
      }
    }
    else{
      
      if (Util.isNotNullOrEmpty(expDate) && expDate.matches("(\\d\\d\\d\\d\\-\\d\\d\\-\\d\\d)") && expDate.length() == 10) {

        Date convertDate = convertStringToDate(expDate);    
        Calendar calendar = Calendar.getInstance();
        calendar.setTime(convertDate); 
        calendar.add(Calendar.DATE, 3);           
        expDate = amitaUserEndDate(calendar.getTime());

      }
      else {

        expDate = "";

      }
      
    }
  }

  if(null != app){
    //comment decache //context.decache(app);
  }

  logger.debug("Exiting Ascension-Rule-IdentityAttributeTarget-Amita-ExpirationDate");
  return expDate;
